// ── Transform: keep top 5 repos, reshape fields ──────────────────────────
const items = $input.all();

// Handle upstream errors gracefully
if (!items[0]?.json?.items) {
  return [{ json: { error: true, message: 'GitHub search returned no items', raw: items[0]?.json } }];
}

const repos = items[0].json.items;

// Sort by stars (API should already sort but let's be safe)
const sorted = repos
  .sort((a, b) => b.stargazers_count - a.stargazers_count)
  .slice(0, 5);

// Reshape to clean objects
const top5 = sorted.map((r, i) => ({
  rank:         i + 1,
  name:         r.full_name,
  description:  r.description || 'No description provided.',
  stars:        r.stargazers_count,
  forks:        r.forks_count,
  language:     r.language || 'Unknown',
  url:          r.html_url,
  owner:        r.owner.login,
  ownerAvatar:  r.owner.avatar_url,
  defaultBranch: r.default_branch || 'main',
  updatedAt:    r.updated_at,
  openIssues:   r.open_issues_count,
  topics:       (r.topics || []).slice(0, 3).join(', '),
}));

// Return as individual items so downstream nodes can loop
return top5.map(r => ({ json: r }));

// Merge README snippet back onto the repo item
const repo = $('Transform — Top 5 Repos').item.json;
const readmeData = $input.item.json;

let readmeSnippet = '(README unavailable)';

if (readmeData?.content) {
  try {
    // README content is base64-encoded
    const decoded = Buffer.from(readmeData.content, 'base64').toString('utf-8');
    // Take first 280 chars as snippet (≈ tweet length)
    readmeSnippet = decoded
      .replace(/[#*`>\[\]]/g, '')  // strip markdown symbols
      .replace(/\n+/g, ' ')        // collapse newlines
      .trim()
      .substring(0, 280);
    if (decoded.length > 280) readmeSnippet += '…';
  } catch (e) {
    readmeSnippet = '(README decode error)';
  }
} else if (readmeData?.error) {
  readmeSnippet = '(No README found)';
}

return {
  json: {
    ...repo,
    readmeSnippet,
  }
};

// Build the Discord embed payload
const items = $input.all().map(i => i.json);
const now = new Date().toUTCString();

// Build one embed field per repo
const fields = items.map(r => ({
  name: `${r.badge}  #${r.rank}  ${r.name}`,
  value: [
    `> ${r.description.substring(0, 120)}`,
    `\`\`\`${r.readmeSnippet.substring(0, 200)}\`\`\``,
    `⭐ ${r.stars.toLocaleString()}  •  🍴 ${r.forks.toLocaleString()}  •  🐛 ${r.openIssues} open issues`,
    `🔤 ${r.language}   🏷️ ${r.topics || 'no topics'}`,
    `🔗 [View on GitHub](${r.url})`,
  ].join('\n'),
  inline: false
}));

const payload = {
  username:   'Morning Brief Bot',
  avatar_url: 'https://github.githubassets.com/images/modules/logos_page/GitHub-Mark.png',
  embeds: [{
    title:       '🌅 GitHub Automation Digest — Top 5 Repos',
    description: `Your daily brief of trending **JavaScript automation** repositories on GitHub.\nGenerated at ${now}`,
    color:       3447003,
    fields:      fields,
    footer: {
      text: 'n8n Morning Brief Workflow  •  Powered by GitHub REST API'
    },
    timestamp: new Date().toISOString()
  }]
};

return [{ json: payload }];

// Log result / handle delivery failure
const result = $input.all()[0];
const ok = result?.json?.code !== undefined ? false : true;

if (!ok) {
  // Would push to Slack/email fallback in production
  console.error('Discord delivery failed:', JSON.stringify(result.json));
  return [{ json: { status: 'discord_failed', detail: result.json, ts: new Date().toISOString() } }];
}

return [{ json: { status: 'delivered', ts: new Date().toISOString() } }];

// Error handler — catches failures from any node in the workflow
const err = $input.all()[0]?.json;
console.error('[ERROR TRIGGER] Workflow error:', JSON.stringify(err));
// In production: send alert email / Slack message
return [{ json: { handled: true, error: err, ts: new Date().toISOString() } }];
